### 3. src/lib/organizations/group-service.ts
Create a helper function for calling the group service directly with service auth JWTs. This follows the same pattern used in the existing POST /api/organizations registration code.

```typescript
import { Agent } from "@atproto/api"
import { GROUP_SERVICE } from "./constants"

/**
 * Call the group service directly with a service auth JWT.
 * The agent must be authenticated to the users PDS.
 * 
 * @param agent - Authenticated Agent for the users PDS
 * @param nsid - The XRPC method NSID (e.g. "app.certified.group.member.list")
 * @param aud - The audience for the service auth JWT (groupDid for most calls, GROUP_SERVICE_DID for registration)
 * @param options.params - Query parameters (for GET requests)
 * @param options.body - JSON body (for POST requests)
 * @returns Parsed JSON response
 * @throws GroupServiceCallError with status and message
 */
export async function callGroupService(
  agent: Agent,
  nsid: string,
  aud: string,
  options?: { params?: Record<string, string | number | undefined>; body?: unknown }
): Promise<unknown> {
  // 1. Get service auth JWT from user PDS
  const { data: { token } } = await agent.com.atproto.server.getServiceAuth({
    aud,
    lxm: nsid,
  })

  // 2. Build URL with query params
  const url = new URL(`${GROUP_SERVICE}/xrpc/${nsid}`)
  if (options?.params) {
    for (const [k, v] of Object.entries(options.params)) {
      if (v !== undefined) url.searchParams.set(k, String(v))
    }
  }

  // 3. Make request
  const isPost = options?.body !== undefined
  const res = await fetch(url.toString(), {
    method: isPost ? "POST" : "GET",
    headers: {
      ...(isPost ? { "Content-Type": "application/json" } : {}),
      Authorization: `Bearer ${token}`,
    },
    ...(isPost ? { body: JSON.stringify(options.body) } : {}),
  })

  if (!res.ok) {
    const errData = await res.json().catch(() => ({ error: "Unknown", message: `Group service error: ${res.status}` }))
    const err = new Error(errData.message || `Group service error: ${res.status}`) as Error & { status: number; code: string }
    err.status = res.status
    err.code = errData.error || "GroupServiceError"
    throw err
  }

  // Some endpoints return empty responses (204-like)
  const text = await res.text()
  return text ? JSON.parse(text) : undefined
}
```

